ALTER TABLE sessions_devices ADD element_rotkey nvarchar(MAX) NOT NULL DEFAULT ('');
ALTER TABLE sessions_devices ADD element_rotkey_iat datetimeoffset DEFAULT (sysdatetimeoffset()) NOT NULL;
ALTER TABLE sessions_devices ADD element_rotkey_exp datetimeoffset DEFAULT (sysdatetimeoffset()) NOT NULL;
ALTER VIEW [dbo].[vw_account_user_sessions] AS SELECT au.element_guid AS user_guid, ur.element_roles AS user_roles, au.element_created_on AS user_created_on, au.element_modified_on AS user_modified_on, au.element_rotkey, au.element_rotkey_iat, au.element_rotkey_exp, us.element_guid AS session_guid, us.element_created_on AS session_created_on, us.element_modified_on AS session_modified_on, sd.element_guid AS device_guid, sd.element_created_on AS device_created_on, sd.element_modified_on AS device_modified_on, sd.element_token, sd.element_token_iat, sd.element_token_exp, sd.element_revoked_at, sd.element_device_fingerprint, sd.element_user_agent, sd.element_ip_last_seen, sd.element_rotkey AS element_device_rotkey, sd.element_rotkey_iat AS element_device_rotkey_iat, sd.element_rotkey_exp AS element_device_rotkey_exp FROM dbo.account_users AS au JOIN dbo.users_sessions AS us ON au.element_guid = us.users_guid JOIN dbo.users_roles AS ur ON au.element_guid = ur.users_guid JOIN dbo.sessions_devices AS sd ON us.element_guid = sd.sessions_guid;
